/**
 * @oas [post] /auth/mfa/factors/{id}/verify
 * operationId: PostMfaFactorsIdVerify
 * summary: Verify and Enable a Multi-Factor Authentication (MFA) Factor
 * x-sidebar-summary: Verify and Enable MFA Factor
 * description: |
 *   Verify a pending multi-factor authentication (MFA) factor by submitting a code generated from
 *   it. A successful verification enables the factor, after which it can be used to verify MFA
 *   challenges during login.
 * x-authenticated: false
 * parameters:
 *   - name: id
 *     in: path
 *     description: The MFA factor's ID.
 *     required: true
 *     schema:
 *       type: string
 * requestBody:
 *   content:
 *     application/json:
 *       schema:
 *         type: object
 *         description: The details required to verify and enable the MFA factor.
 *         required:
 *           - code
 *         properties:
 *           code:
 *             type: string
 *             title: code
 *             description: The verification code generated by the MFA factor (for example, the current TOTP code from the authenticator app).
 * x-codeSamples:
 *   - lang: JavaScript
 *     label: JS SDK
 *     source: |-
 *       import Medusa from "@medusajs/js-sdk"
 * 
 *       export const sdk = new Medusa({
 *         baseUrl: import.meta.env.VITE_BACKEND_URL || "/",
 *         debug: import.meta.env.DEV,
 *         auth: {
 *           type: "session",
 *         },
 *       })
 * 
 *       const { mfa_factor } = await sdk.auth.mfa.verify("authmfa_123", {
 *         code: "123456"
 *       })
 *   - lang: Shell
 *     label: cURL
 *     source: |-
 *       curl -X POST '{backend_url}/auth/mfa/factors/{id}/verify' \
 *       -H 'Content-Type: application/json' \
 *       --data-raw '{
 *         "code": "{value}"
 *       }'
 * tags:
 *   - Mfa
 * responses:
 *   "200":
 *     description: OK
 *   "400":
 *     $ref: "#/components/responses/400_error"
 *   "401":
 *     $ref: "#/components/responses/unauthorized"
 *   "404":
 *     $ref: "#/components/responses/not_found_error"
 *   "409":
 *     $ref: "#/components/responses/invalid_state_error"
 *   "422":
 *     $ref: "#/components/responses/invalid_request_error"
 *   "500":
 *     $ref: "#/components/responses/500_error"
 * 
*/

